var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。","ENG":"that you'll be with it, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called it to your office. It said it'd be here soon.","TWN":"做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"결국 저도 이렇게 되는군요.","JPN":"結局、私もこうなるのですね。","ENG":"So my final day has come.","TWN":"結果，我也變成這樣了呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"다른 오래된 기체들과 마찬가지로 저 또한 분해되어 재제조 공정을 거치게 되겠죠.","JPN":"他の古びた機体同様、私も分解され、再製造工程に回されることでしょう。","ENG":"Like all the other outdated models, I'm going to be disassembled and recycled.","TWN":"我也會和其他舊機體一樣被分解，經過再製造工程吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"하지만 너무 신경 쓰지 마십시오.","JPN":"ですが、気になさることはありません。","ENG":"But don't worry.","TWN":"但請您不要太在意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"저와 같은 소모성 병기가 조기 퇴역을 하는 것은 진작부터 각오하고 있던 바입니다.","JPN":"私は使い捨ての兵器なのですから、早期退役することは元より覚悟の上です。","ENG":"It's quite common for an expendable weapons like myself to get retired ahead of its expected disposal date.","TWN":"像我這種消耗性兵器，早就做好提前退役的心理準備了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"다음 생에는 스스로 움직일 수 있는 전차로 태어났으면 좋겠군요. 그럼 이만......","JPN":"来世では、自律型の戦車に生まれ変わりたいものです。ではこれで……","ENG":"But... I sincerely hope that I will become a self-sufficient tank in the next life. Goodbye, then.","TWN":"下輩子能成為可以自主移動的戰車就好了。那就再見了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"아, 저를 직원으로서 고용하신단 말씀이신가요?","JPN":"あ、私を社員として雇うということですか？","ENG":"Ah, you were trying to say that you want to hire me?","TWN":"啊，您是要把我當成員工來雇用嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"......감수성 프로세스 종료. 직장상사 대응 커뮤니케이션 기법 활성화.","JPN":"……感受性プロセス終了。職場上司対応コミュニケーション技法アクティベーション。","ENG":"Protocol: Drama Queen terminated. Operating the communication protocol: Polite Office Worker.","TWN":"……終止情感程序。啟動對應職場上司的通信技術。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"이렇게 불러주셔서 감사합니다, 명령권자님.","JPN":"こうしてお呼びいただき、感謝しております。コマンダー。","ENG":"Thank you for calling me in, Commander.","TWN":"謝謝您呼叫我，指揮官大人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"평소엔 다른 분들에게 도움을 받는 신세지만, 저도 언제나 현장에선 최선을 다하고 있었습니다.","JPN":"常日頃から他の方々に助けていただいておりますが、私も現場ではいつも最善を尽くしておりました。","ENG":"I frequently receive help from others, but I've always done my best out in the field.","TWN":"雖然平時受到他人許多的幫助，但我在作戰現場一直都是全力以赴。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"저의 그런 노력이 명령권자 님에게 전해진 것 같아 기쁘고 보람찹니다.","JPN":"これまでの私の努力がコマンダーに伝わったようで、感激と達成感を覚えております。","ENG":"I'm glad and more than happy that all my past efforts have been acknowledged, Commander.","TWN":"很高興我的努力有傳達給指揮官大人，很有成就感。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"이러한 의존적 관계가 유지될 수 있도록, 앞으로도 회사의 성실한 종이 되겠습니다.","JPN":"このような依存関係を持続できるように、これからも誠実な社員として努めてまいります。","ENG":"I'll be a faithful servant to the company, so that this dependent relationship could be maintained.","TWN":"為了能夠維持這個信賴關係，今後我將成為公司的一名認真員工。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"......그럼 이제 수레를 부탁 드려도 될까요?","JPN":"……では、運搬をお願いしてもよろしいでしょうか？","ENG":"Now, could you push this wagon?","TWN":"……那現在，我可以要個推車嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};